void fmi2_do_step_fmumodelica_medoff_template_1_0599e848(void *fmu_wr,
                        double current_time,
                        double step_size,
                        int no_prior_fmu_state)
{
    /* Make sure we only take a step when time has advanced from the most recent time */
    if (current_time > previous_time_fmumodelica_medoff_template_1_0599e848) {
        previous_time_fmumodelica_medoff_template_1_0599e848 = current_time;
        wrapper_do_step(fmu_wr,
                        current_time,
                        step_size,
                        no_prior_fmu_state,
                        &ModelicaError);
    }
}
        
